import { prisma } from "@/lib/prisma";
import { Plus, Search, Edit2, Package, Tag, Layers, ArrowUpDown, Image as ImageIcon } from "lucide-react";
import Link from "next/link";
import { revalidatePath } from "next/cache";
import DeleteProductButton from "@/components/DeleteProductButton";

async function deleteProduct(formData: FormData) {
  "use server";
  const id = formData.get("id") as string;
  await prisma.product.delete({ where: { id } });
  revalidatePath("/estoque");
  revalidatePath("/");
}

export default async function InventoryPage({
  searchParams,
}: {
  searchParams: Promise<{ q?: string }>;
}) {
  const query = (await searchParams).q || "";
  
  const products = await prisma.product.findMany({
    where: {
      OR: [
        { name: { contains: query } },
        { category: { contains: query } },
      ],
    },
    orderBy: { name: "asc" },
  });

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
        <div className="space-y-1">
          <div className="flex items-center gap-2 text-scout-green font-black uppercase text-[10px] tracking-[0.4em]">
            <Layers className="w-3 h-3" />
            Gestão de Patrimônio
          </div>
          <h1 className="text-4xl font-black text-[var(--foreground)] tracking-tight">Estoque da Lojinha</h1>
          <p className="text-[var(--muted)] font-medium">Controle de uniformes, distintivos e acessórios</p>
        </div>
        <Link href="/estoque/novo" className="btn-scout-primary shadow-lg shadow-scout-green/20 h-14 px-8 text-base">
          <Plus className="w-6 h-6" />
          Novo Produto
        </Link>
      </div>

      <div className="grid grid-cols-1 gap-6">
        <div className="bg-[var(--card-bg)] rounded-2xl shadow-sm border border-[var(--border)] overflow-hidden">
          <div className="p-6 border-b border-[var(--border)] bg-[var(--background)]/50">
            <div className="relative">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-[var(--muted)] w-5 h-5" />
              <form action="/estoque" method="GET">
                <input
                  type="text"
                  name="q"
                  defaultValue={query}
                  placeholder="Pesquisar por nome ou categoria..."
                  className="w-full pl-12 pr-4 py-4 input-scout border-none shadow-none ring-1 ring-[var(--border)] focus:ring-2"
                />
              </form>
            </div>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-[var(--background)]/30 text-[10px] font-black text-[var(--muted)] uppercase tracking-[0.2em] border-b border-[var(--border)]">
                  <th className="py-5 px-6">Produto</th>
                  <th className="py-5 px-6">Categoria</th>
                  <th className="py-5 px-6 text-right">Preço Unitário</th>
                  <th className="py-5 px-6 text-center">Disponível</th>
                  <th className="py-5 px-6 text-right">Ações</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-[var(--border)]">
                {products.map((product) => (
                  <tr key={product.id} className="hover:bg-scout-khaki/30 transition-colors group">
                    <td className="py-6 px-6">
                      <div className="flex items-center gap-4">
                        <div className="w-16 h-16 bg-[var(--background)] rounded-xl border border-[var(--border)] flex items-center justify-center text-[var(--muted)] overflow-hidden shrink-0 group-hover:border-scout-green/30 transition-all shadow-sm">
                          {product.image ? (
                            <img src={product.image} alt={product.name} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" />
                          ) : (
                            <Package className="w-8 h-8 opacity-20" />
                          )}
                        </div>
                        <div>
                          <div className="font-bold text-[var(--foreground)] text-lg leading-tight">{product.name}</div>
                          <div className="text-sm text-[var(--muted)] line-clamp-1 max-w-xs">{product.description || "Sem descrição"}</div>
                        </div>
                      </div>
                    </td>
                    <td className="py-6 px-6">
                      <div className="flex items-center gap-2">
                        <Tag className="w-3 h-3 text-scout-blue opacity-40" />
                        <span className="text-xs font-black uppercase tracking-widest text-scout-blue">
                          {product.category || "Geral"}
                        </span>
                      </div>
                    </td>
                    <td className="py-6 px-6 text-right font-black text-[var(--foreground)]">
                      R$ {product.price.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                    </td>
                    <td className="py-6 px-6 text-center">
                      <div className="flex flex-col items-center">
                        <span className={`text-xl font-black ${
                          product.stock <= 5 ? "text-red-500" : "text-scout-green"
                        }`}>
                          {product.stock}
                        </span>
                        {product.stock <= 5 && (
                          <span className="text-[8px] font-black uppercase text-red-500 tracking-tighter">Reposição Crítica</span>
                        )}
                      </div>
                    </td>
                    <td className="py-6 px-6">
                      <div className="flex justify-end items-center gap-2">
                        <Link 
                          href={`/estoque/editar/${product.id}`}
                          className="w-10 h-10 flex items-center justify-center text-[var(--muted)] hover:text-scout-blue hover:bg-scout-blue/5 rounded-xl transition-all"
                          title="Editar"
                        >
                          <Edit2 className="w-5 h-5" />
                        </Link>
                        <DeleteProductButton productId={product.id} action={deleteProduct} />
                      </div>
                    </td>
                  </tr>
                ))}
                {products.length === 0 && (
                  <tr>
                    <td colSpan={5} className="py-24 text-center">
                      <div className="flex flex-col items-center gap-4 opacity-30">
                        <Search className="w-16 h-16" />
                        <p className="font-bold text-xl uppercase tracking-widest">Nenhum item encontrado</p>
                      </div>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
          
          <div className="p-6 bg-gray-50/30 border-t border-gray-100 flex justify-between items-center text-[10px] font-black text-gray-400 uppercase tracking-[0.2em]">
            <div>Total de Itens: {products.length}</div>
            <div>"Sempre Alerta"</div>
          </div>
        </div>
      </div>
    </div>
  );
}
